from flask import Flask, request
from pymongo import MongoClient

app = Flask(__name__)
client = MongoClient('localhost', 27017)
db = client['mydatabase']    # replace 'mydatabase' with your database name
users_collection = db['users']   # or whatever you call your users collection

@app.route('/user/add', methods=['POST'])
def add_user():
    user = request.json
    result = users_collection.insert_one(user)
    return {'result': str(result.acknowledged)}

@app.route('/user/get/<string:username>', methods=['GET'])
def get_user(username):
    user = users_collection.find_one({"username": username})
    if user:
        return {'result': user}
    else:
        return {'error': 'User not found'}, 404
        
@app.route('/user/update', methods=['PUT'])
def update_user():
    user = request.json
    result = users_collection.replace_one({'username': user['username']}, user)
    return {'result': str(result.acknowledged)}
    
@app.route('/user/delete', methods=['DELETE'])
def delete_user():
    username = request.args.get('username')  # assume we get the username from URL parameters
    result = users_collection.delete_one({'username': username})
    return {'result': str(result.acknowledged)}

if __name__ == '__main__':
    app.run(debug=True)